import { test as base, expect } from '@playwright/test';

type Fixtures = {
  authToken: string;      // worker scope — chỉ lấy token 1 lần
  apiClient: ApiClient;   // test scope — fresh instance mỗi test
  adminPage: Page;        // dùng authToken bên trong
};

export const test = base.extend<Fixtures>({
  // Worker scope: chạy 1 lần, share cho tất cả test trong worker
  authToken: [async ({}, use) => {
    const token = await fetchAuthToken('admin@test.com', 'pass');
    await use(token);
    // teardown: có thể revoke token nếu cần
  }, { scope: 'worker' }],

  // Test scope: dùng authToken (fixture khác) làm dependency
  adminPage: async ({ page, authToken }, use) => {
    await page.setExtraHTTPHeaders({ Authorization: `Bearer ${authToken}` });
    await page.goto('/admin');
    await use(page);
  },

  // Override built-in 'page' — inject cookie cho mọi test
  page: async ({ page }, use) => {
    await page.context().addCookies([{ name: 'locale', value: 'vi' }]);
    await use(page); // page bây giờ luôn có cookie locale=vi
  },
});

test('admin sees dashboard', async ({ adminPage }) => {
  await expect(adminPage.getByRole('heading', { name: 'Dashboard' })).toBeVisible();
});

// fixtures/LoginPage.ts — đóng gói toàn bộ login flow
export class LoginPage {
  constructor(private page: Page) {}

  async goto() {
    await this.page.goto('/login');
  }
  async login(email: string, password: string) {
    await this.page.getByLabel('Email').fill(email);
    await this.page.getByLabel('Mật khẩu').fill(password);
    await this.page.getByRole('button', { name: 'Đăng nhập' }).click();
    await this.page.waitForURL('/dashboard'); // chờ redirect
  }
  async getErrorMessage() {
    return this.page.getByRole('alert').textContent();
  }
}

// fixtures/index.ts — kết hợp POM + Fixture
import { test as base } from '@playwright/test';
type MyFixtures = { loginPage: LoginPage };

export const test = base.extend<MyFixtures>({
  loginPage: async ({ page }, use) => {
    await use(new LoginPage(page));
  },
});

